+/**
+ * Priority-based notification router.
+ *
+ * Routes notifications to specific channel handlers based on priority:
+ * - urgent → SMS channel
+ * - normal → email channel
+ * - low → webhook channel
+ *
+ * This replaces the previous broadcast approach where all channels
+ * received every notification regardless of priority.
+ */
+
+import type { NotificationChannel, NotificationEvent } from './notification.service.js';
+import { Logger } from '../utils/logger.js';
+
+export type NotificationPriority = 'urgent' | 'normal' | 'low';
+
+export interface PrioritizedNotification extends NotificationEvent {
+  priority: NotificationPriority;
+}
+
+export class PriorityRouter {
+  private logger = new Logger('PriorityRouter');
+  private routes = new Map<NotificationPriority, NotificationChannel>();
+
+  /**
+   * Register a channel handler for a specific priority level.
+   */
+  registerRoute(priority: NotificationPriority, channel: NotificationChannel): void {
+    this.routes.set(priority, channel);
+    this.logger.info(`Registered channel for priority: ${priority}`);
+  }
+
+  /**
+   * Route a notification to the appropriate channel based on its priority.
+   * Throws if no channel is registered for the given priority.
+   */
+  async route(notification: PrioritizedNotification): Promise<void> {
+    const channel = this.routes.get(notification.priority);
+    if (!channel) {
+      throw new Error(`No channel registered for priority: ${notification.priority}`);
+    }
+
+    this.logger.info(
+      `Routing ${notification.priority} notification to registered channel: ${notification.subject}`,
+    );
+    await channel.handle(notification);
+  }
+
+  /**
+   * Check whether a channel is registered for the given priority.
+   */
+  hasRoute(priority: NotificationPriority): boolean {
+    return this.routes.has(priority);
+  }
+}

