/**
 * SMS notification channel — delivers notifications via SMS.
 * Stores delivered messages in-memory for testability.
 */
export class SmsNotificationChannel implements NotificationChannel {
  private deliveredMessages: NotificationEvent[] = [];
  private logger = new Logger('SmsChannel');

  handle(event: NotificationEvent): void {
    this.logger.info(`Sending SMS to ${event.recipient}: ${event.subject}`);
    this.deliveredMessages.push({ ...event });
  }

  getDeliveredMessages(): NotificationEvent[] {
    return [...this.deliveredMessages];
  }

  clearDeliveredMessages(): void {
    this.deliveredMessages = [];
  }
}

