  handle(event: NotificationEvent): void {
    this.logger.info(`Sending webhook for ${event.recipient}: ${event.subject}`);
    this.deliveredPayloads.push({ ...event });
  }

  getDeliveredPayloads(): NotificationEvent[] {
    return [...this.deliveredPayloads];
