import { describe, it, expect, beforeEach } from 'vitest';
import { PriorityRouter } from '../../src/services/priority-router.js';
import type { PrioritizedNotification } from '../../src/services/priority-router.js';
import {
  EmailNotificationChannel,
  SmsNotificationChannel,
  WebhookNotificationChannel,
} from '../../src/services/notification.service.js';

describe('PriorityRouter', () => {
  let router: PriorityRouter;
  let smsChannel: SmsNotificationChannel;
  let emailChannel: EmailNotificationChannel;
  let webhookChannel: WebhookNotificationChannel;

  beforeEach(() => {
    router = new PriorityRouter();
    smsChannel = new SmsNotificationChannel();
    emailChannel = new EmailNotificationChannel();
    webhookChannel = new WebhookNotificationChannel();

    router.registerRoute('urgent', smsChannel);
    router.registerRoute('normal', emailChannel);
    router.registerRoute('low', webhookChannel);
  });

  function makeNotification(priority: PrioritizedNotification['priority']): PrioritizedNotification {
    return {
      type: 'test',
      recipient: 'user@example.com',
      subject: 'Test Subject',
      body: 'Test body',
      priority,
    };
  }

  describe('routing by priority', () => {
    it('should route urgent notifications to SMS channel', async () => {
      await router.route(makeNotification('urgent'));

      expect(smsChannel.getDeliveredMessages()).toHaveLength(1);
      expect(emailChannel.getDeliveredEmails()).toHaveLength(0);
      expect(webhookChannel.getDeliveredPayloads()).toHaveLength(0);
    });

    it('should route normal notifications to email channel', async () => {
      await router.route(makeNotification('normal'));

      expect(smsChannel.getDeliveredMessages()).toHaveLength(0);
      expect(emailChannel.getDeliveredEmails()).toHaveLength(1);
      expect(webhookChannel.getDeliveredPayloads()).toHaveLength(0);
    });

    it('should route low-priority notifications to webhook channel', async () => {
      await router.route(makeNotification('low'));

      expect(smsChannel.getDeliveredMessages()).toHaveLength(0);
      expect(emailChannel.getDeliveredEmails()).toHaveLength(0);
      expect(webhookChannel.getDeliveredPayloads()).toHaveLength(1);
    });
  });

  describe('route registration', () => {
    it('should report registered routes via hasRoute', () => {
      const emptyRouter = new PriorityRouter();
      expect(emptyRouter.hasRoute('urgent')).toBe(false);

      emptyRouter.registerRoute('urgent', smsChannel);
      expect(emptyRouter.hasRoute('urgent')).toBe(true);
    });

    it('should throw when routing to an unregistered priority', async () => {
      const emptyRouter = new PriorityRouter();

      await expect(emptyRouter.route(makeNotification('urgent'))).rejects.toThrow(
        'No channel registered for priority: urgent',
      );
    });
  });

  describe('notification delivery', () => {
    it('should pass full notification payload to the channel', async () => {
      const notification: PrioritizedNotification = {
        type: 'order:confirmation',
        recipient: 'alice@example.com',
        subject: 'Order Confirmed',
        body: 'Your order is confirmed.',
        priority: 'normal',
      };

      await router.route(notification);

      const emails = emailChannel.getDeliveredEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.type).toBe('order:confirmation');
      expect(emails[0]?.recipient).toBe('alice@example.com');
      expect(emails[0]?.subject).toBe('Order Confirmed');
      expect(emails[0]?.body).toBe('Your order is confirmed.');
    });

    it('should handle multiple notifications across priorities', async () => {
      await router.route(makeNotification('urgent'));
      await router.route(makeNotification('normal'));
      await router.route(makeNotification('low'));
      await router.route(makeNotification('urgent'));

      expect(smsChannel.getDeliveredMessages()).toHaveLength(2);
      expect(emailChannel.getDeliveredEmails()).toHaveLength(1);
      expect(webhookChannel.getDeliveredPayloads()).toHaveLength(1);
    });
  });
});

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('NotificationService', () => {
  let eventBus: EventBus;
  let service: NotificationService;

  beforeEach(() => {
    eventBus = new EventBus();
    statusChangeCallbacks.clear();
    service = new NotificationService(eventBus);
    resetNotificationIdCounter();
  });

  describe('order:created handler', () => {
    it('should send notification on order created', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.recipient).toBe('alice@example.com');
      expect(notifications[0]?.subject).toContain('Order Confirmation');
      expect(notifications[0]?.body).toContain('Widget x2');
      expect(notifications[0]?.body).toContain('$20.00');
    });

    it('should include all items in notification body', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
            { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
          ],
          total: 45,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications[0]?.body).toContain('Widget x2');
      expect(notifications[0]?.body).toContain('Gadget x1');
    });
  });

  describe('order:status-changed handler', () => {
    it('should send notification on status change', () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      statusChangeCallbacks.notify(event);

      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.subject).toContain('Order Update');
      expect(notifications[0]?.body).toContain('pending');
      expect(notifications[0]?.body).toContain('confirmed');
    });
  });

  describe('notification management', () => {
    it('should count notifications', () => {
      expect(service.getNotificationCount()).toBe(0);

      statusChangeCallbacks.notify({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(service.getNotificationCount()).toBe(1);
    });

    it('should filter by recipient', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(service.getNotificationsForRecipient('alice@example.com')).toHaveLength(1);
      expect(service.getNotificationsForRecipient('bob@example.com')).toHaveLength(0);
    });

    it('should clear notifications', () => {
      statusChangeCallbacks.notify({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      service.clearNotifications();
      expect(service.getNotificationCount()).toBe(0);
    });

    it('should generate sequential notification IDs', () => {
      statusChangeCallbacks.notify({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });
      statusChangeCallbacks.notify({
        type: 'order:status-changed',
        order: {
          id: 'order-2',
          userId: 'user-1',
          items: [],
          total: 30,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      });

      const notifications = service.getNotifications();
      expect(notifications[0]?.id).toBe('notif-0001');
      expect(notifications[1]?.id).toBe('notif-0002');
    });
  });
});

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  EmailNotificationChannel,
  SmsNotificationChannel,
  WebhookNotificationChannel,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import type { NotificationEvent } from '../../src/services/notification.service.js';
import { PriorityRouter } from '../../src/services/priority-router.js';
import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('Priority-Based Channel Routing', () => {
  let eventBus: EventBus;
  let router: PriorityRouter;
  let emailChannel: EmailNotificationChannel;
  let smsChannel: SmsNotificationChannel;
  let webhookChannel: WebhookNotificationChannel;
  let service: NotificationService;

  beforeEach(() => {
    eventBus = new EventBus();
    statusChangeCallbacks.clear();

    emailChannel = new EmailNotificationChannel();
    smsChannel = new SmsNotificationChannel();
    webhookChannel = new WebhookNotificationChannel();

    router = new PriorityRouter();
    router.registerRoute('urgent', smsChannel);
    router.registerRoute('normal', emailChannel);
    router.registerRoute('low', webhookChannel);

    service = new NotificationService(eventBus, router);
    resetNotificationIdCounter();
  });

  it('should route order confirmation (normal priority) to email channel', async () => {
    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [
          { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
        ],
        total: 20,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    const emails = emailChannel.getDeliveredEmails();
    expect(emails).toHaveLength(1);
    expect(emails[0]?.type).toBe('order:confirmation');
    expect(emails[0]?.recipient).toBe('alice@example.com');
    expect(emails[0]?.subject).toContain('Order Confirmation');
    expect(emails[0]?.body).toContain('Widget x2');
    expect(emails[0]?.body).toContain('$20.00');

    // Should NOT go to SMS or webhook
    expect(smsChannel.getDeliveredMessages()).toHaveLength(0);
    expect(webhookChannel.getDeliveredPayloads()).toHaveLength(0);
  });

  it('should route status update (urgent priority) to SMS channel', () => {
    const event: OrderStatusChangedEvent = {
      type: 'order:status-changed',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [],
        total: 20,
        status: 'confirmed',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      previousStatus: 'pending',
      newStatus: 'confirmed',
      timestamp: new Date(),
    };

    statusChangeCallbacks.notify(event);

    const messages = smsChannel.getDeliveredMessages();
    expect(messages).toHaveLength(1);
    expect(messages[0]?.type).toBe('order:status-update');
    expect(messages[0]?.recipient).toBe('user-1');
    expect(messages[0]?.subject).toContain('Order Update');
    expect(messages[0]?.body).toContain('pending');
    expect(messages[0]?.body).toContain('confirmed');

    // Should NOT go to email or webhook
    expect(emailChannel.getDeliveredEmails()).toHaveLength(0);
    expect(webhookChannel.getDeliveredPayloads()).toHaveLength(0);
  });

  it('should support custom NotificationChannel implementations via router', async () => {
    const captured: NotificationEvent[] = [];
    const customChannel = {
      handle(event: NotificationEvent) {
        captured.push(event);
      },
    };

    const customRouter = new PriorityRouter();
    customRouter.registerRoute('normal', customChannel);
    const customService = new NotificationService(eventBus, customRouter);

    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [
          { productId: 'p1', name: 'Item', quantity: 1, unitPrice: 10 },
        ],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Carol',
        email: 'carol@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(captured).toHaveLength(1);
    expect(captured[0]?.recipient).toBe('carol@example.com');

    void customService;
  });

  it('should clear delivered emails', async () => {
    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [
          { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
        ],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);
    expect(emailChannel.getDeliveredEmails()).toHaveLength(1);

    emailChannel.clearDeliveredEmails();
    expect(emailChannel.getDeliveredEmails()).toHaveLength(0);
  });
});
